import React, { useState, useRef, useEffect } from 'react';
import { askChatbot } from '../services/aiService';
import { getCachedFaq } from '../utils/offlineStorage';

/**
 * Chatbot page – AI assistant with online/offline dual mode.
 *
 * Online mode:  sends message to POST /api/chatbot/ask
 * Offline mode: matches user message against locally cached FAQ in IndexedDB
 */
function Chatbot() {
  const [messages, setMessages] = useState([
    {
      id: 1,
      role: 'bot',
      text: 'Hello! I\'m your AI learning assistant. Ask me anything about the platform, courses, or quizzes. I work even when you\'re offline! 🤖',
      source: null,
    },
  ]);
  const [input, setInput]         = useState('');
  const [sending, setSending]     = useState(false);
  const [isOnline, setIsOnline]   = useState(navigator.onLine);
  const bottomRef = useRef(null);

  useEffect(() => {
    const handleOnline  = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online',  handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online',  handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addMessage = (role, text, source = null) => {
    setMessages((prev) => [
      ...prev,
      { id: Date.now(), role, text, source },
    ]);
  };

  const handleSend = async () => {
    const text = input.trim();
    if (!text || sending) return;

    addMessage('user', text);
    setInput('');
    setSending(true);

    try {
      if (isOnline) {
        // Online mode: send to backend for FAQ match / AI response
        const { data } = await askChatbot(text);
        addMessage('bot', data.answer, data.source);
      } else {
        // Offline mode: local FAQ keyword matching
        const answer = await matchOfflineFaq(text);
        addMessage('bot', answer, 'OFFLINE_FAQ');
      }
    } catch (err) {
      addMessage('bot', 'Sorry, something went wrong. Please try again.', 'ERROR');
    } finally {
      setSending(false);
    }
  };

  /**
   * Matches the user's message against cached FAQ entries.
   * Tokenises the message and checks for keyword overlap.
   */
  async function matchOfflineFaq(message) {
    try {
      const faqList = await getCachedFaq();
      if (faqList.length === 0) {
        return 'I\'m offline and the FAQ database hasn\'t been cached yet. Please connect to the internet and log in again to enable offline support.';
      }

      const tokens = message.toLowerCase().split(/\W+/).filter((t) => t.length > 2);

      for (const faq of faqList) {
        const keywords = faq.keyword.toLowerCase().split(',').map((k) => k.trim());
        if (keywords.some((k) => tokens.includes(k))) {
          return faq.answer;
        }
      }

      return 'I\'m offline and couldn\'t find an answer in my local FAQ. Please try again when you\'re connected for a more detailed response.';
    } catch {
      return 'Unable to access offline FAQ database.';
    }
  }

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={styles.header}>
        <div>
          <h2 style={styles.title}>🤖 AI Learning Assistant</h2>
          <p style={styles.subtitle}>
            {isOnline
              ? 'Online – Full AI responses available'
              : 'Offline – Using local FAQ database'}
          </p>
        </div>
        <div style={{ ...styles.statusDot, background: isOnline ? '#22c55e' : '#f59e0b' }}>
          {isOnline ? '🟢 Online' : '🟡 Offline'}
        </div>
      </div>

      {/* Message list */}
      <div style={styles.messages}>
        {messages.map((msg) => (
          <div
            key={msg.id}
            style={{
              ...styles.message,
              ...(msg.role === 'user' ? styles.userMsg : styles.botMsg),
            }}
          >
            <div style={styles.msgBubble(msg.role)}>
              {msg.text}
            </div>
            {msg.source && msg.role === 'bot' && (
              <div style={styles.source}>
                {msg.source === 'FAQ'         && '📋 FAQ'}
                {msg.source === 'AI_MOCK'     && '🤖 AI'}
                {msg.source === 'OFFLINE_FAQ' && '📴 Offline FAQ'}
                {msg.source === 'ERROR'       && '⚠ Error'}
              </div>
            )}
          </div>
        ))}
        {sending && (
          <div style={styles.message}>
            <div style={styles.msgBubble('bot')}>
              <Typing />
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* Input area */}
      <div style={styles.inputArea}>
        <textarea
          style={styles.input}
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder="Ask anything… (Enter to send)"
          rows={2}
          disabled={sending}
        />
        <button
          onClick={handleSend}
          style={{ ...styles.sendBtn, opacity: sending || !input.trim() ? 0.5 : 1 }}
          disabled={sending || !input.trim()}
        >
          Send ↑
        </button>
      </div>

      {/* Suggested questions */}
      <div style={styles.suggestions}>
        <span style={styles.suggestLabel}>Try asking:</span>
        {SUGGESTIONS.map((s) => (
          <button key={s} style={styles.suggest} onClick={() => setInput(s)}>
            {s}
          </button>
        ))}
      </div>
    </div>
  );
}

const SUGGESTIONS = [
  'How does offline sync work?',
  'How is my quiz score calculated?',
  'How do I start a course?',
  'How can I see my progress?',
];

function Typing() {
  return <span style={{ letterSpacing: '3px' }}>...</span>;
}

const styles = {
  page: {
    maxWidth: '720px', margin: '0 auto', padding: '24px 20px',
    display: 'flex', flexDirection: 'column', height: 'calc(100vh - 100px)',
  },
  header: {
    display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start',
    marginBottom: '16px',
  },
  title:    { fontSize: '20px', fontWeight: '700', color: '#111827' },
  subtitle: { fontSize: '13px', color: '#6b7280', marginTop: '2px' },
  statusDot: {
    padding: '6px 12px', borderRadius: '20px', fontSize: '12px',
    background: '#dcfce7', color: '#166534', fontWeight: '500',
  },
  messages: {
    flex: 1, overflowY: 'auto', padding: '12px',
    background: '#f8fafc', borderRadius: '12px', border: '1px solid #e5e7eb',
    display: 'flex', flexDirection: 'column', gap: '12px', marginBottom: '12px',
  },
  message: { display: 'flex', flexDirection: 'column' },
  userMsg: { alignItems: 'flex-end' },
  botMsg:  { alignItems: 'flex-start' },
  msgBubble: (role) => ({
    maxWidth: '80%',
    padding: '10px 16px',
    borderRadius: role === 'user' ? '18px 18px 4px 18px' : '18px 18px 18px 4px',
    background: role === 'user' ? '#4f46e5' : '#fff',
    color: role === 'user' ? '#fff' : '#1e293b',
    fontSize: '14px',
    lineHeight: '1.5',
    boxShadow: '0 1px 4px rgba(0,0,0,0.08)',
    border: role === 'bot' ? '1px solid #e5e7eb' : 'none',
  }),
  source: { fontSize: '11px', color: '#9ca3af', marginTop: '3px', paddingLeft: '4px' },
  inputArea: { display: 'flex', gap: '8px', marginBottom: '10px', alignItems: 'flex-end' },
  input: {
    flex: 1, padding: '10px 14px', border: '1px solid #d1d5db', borderRadius: '10px',
    fontSize: '14px', resize: 'none', outline: 'none', lineHeight: '1.5',
    fontFamily: 'inherit',
  },
  sendBtn: {
    padding: '10px 20px', background: '#4f46e5', color: '#fff', border: 'none',
    borderRadius: '10px', cursor: 'pointer', fontWeight: '600', fontSize: '14px',
    alignSelf: 'stretch',
  },
  suggestions: { display: 'flex', gap: '6px', flexWrap: 'wrap', alignItems: 'center' },
  suggestLabel: { fontSize: '12px', color: '#9ca3af' },
  suggest: {
    fontSize: '12px', background: '#f3f4f6', color: '#4b5563', border: '1px solid #e5e7eb',
    padding: '4px 10px', borderRadius: '16px', cursor: 'pointer',
  },
};

export default Chatbot;
